func fetchWithRetry(request: URLRequest, retries: Int = 3) {
    let task = URLSession.shared.dataTask(with: request) { data, response, error in
        if let error = error as? URLError, error.code == .networkConnectionLost, retries > 0 {
            DispatchQueue.global().asyncAfter(deadline: .now() + 2) {
                fetchWithRetry(request: request, retries: retries - 1)
            }
            return
        }
        // Handle response
    }
    task.resume()
}

