func downsample(imageAt url: URL, to size: CGSize) -> UIImage {
    let imageSourceOptions = [kCGImageSourceShouldCache: false] as CFDictionary
    let imageSource = CGImageSourceCreateWithURL(url as CFURL, imageSourceOptions)!
    let maxDimension = max(size.width, size.height)
    let downsampleOptions = [
        kCGImageSourceCreateThumbnailFromImageAlways: true,
        kCGImageSourceShouldCacheImmediately: true,
        kCGImageSourceCreateThumbnailWithTransform: true,
        kCGImageSourceThumbnailMaxPixelSize: maxDimension
    ] as CFDictionary
    return CGImageSourceCreateThumbnailAtIndex(imageSource, 0, downsampleOptions).flatMap { UIImage(cgImage: $0) }!
}

